%Psiparameters	% Set up the threshold range for estimation	minThres = log10(0.01); 	maxThres = log10(1); 	thresStep = 0.05;		% Set up the slope range for estimation	minSlope=1;	maxSlope=4;	slopeStep=.25; % octave units		% Possible contrast to be presented in an experimental section	minCont=log10(.01);	maxCont=log10(1);	contStep = 0.05;		pcorr=0.86;		% percentage correct at threshold	miss = 0.04;	% miss level	gamma = .5;		% Guessing factor. It is 0.5 for 2AFCPSIpar=PsiInit(minThres,maxThres,thresStep,...		minSlope,maxSlope,slopeStep,minCont,maxCont,contStep,...		miss, gamma,pcorr)% Initial expntrial=40;%Define observerobsThreshold=0.1;obsSlope=3;p=0.5+0.5*dprime(log10(obsThreshold),obsSlope,PSIpar.contRange,pcorr);plot(PSIpar.contRange,p,PSIpar.contRange(16),p(16),'o',PSIpar.contRange(24),p(24),'o')%experimental loop begin herefor i = 1: ntrial	%place contrast	contIndex=PsiPlace(PSIpar);	tContrast=PSIpar.contRange(contIndex);		% Present stimulus		% get response	if 	p(contIndex) > rand(1)		response=1;	else		response=0;	end	% Update Psi    [thresEst, slopeEst, PSIpar]=PsiUpdate(PSIpar, contIndex, response);	threshold(i)=thresEst;	slope(i)=slopeEst;	rr(i)=response;	placement(i)=tContrast;endsubplot(2,2,1)plot(placement*20)subplot(2,2,2)plot(rr)subplot(2,2,3)plot(threshold*20)title('threshold')subplot(2,2,4)plot(slope)title('slope')[thresEst*20 slopeEst]